  8	  MenuToggle
  9	} from '@patternfly/react-core';
 10	import * as React from 'react';
 11	import { connect } from 'react-redux';
 12	import { bindActionCreators } from 'redux';
 13	import { HistoryManager, URLParam } from '../../../app/History';
 14	import { KialiAppState, MeshToolbarState } from '../../../store/Store';
 15	import {
 16	  BoundingClientAwareComponent,
 17	  PropertyType
 18	} from 'components/BoundingClientAwareComponent/BoundingClientAwareComponent';
 19	import { KialiIcon } from 'config/KialiIcon';
 20	import {
 21	  containerStyle,
 22	  itemStyleWithInfo,
 23	  itemStyleWithoutInfo,
 24	  menuStyle,
 25	  menuEntryStyle,
 26	  titleStyle
 27	} from 'styles/DropdownStyles';
 28	import { KialiDispatch } from 'types/Redux';
 29	import { serverConfig } from '../../../config';
 30	import { infoStyle } from 'styles/IconStyle';
 31	import { INITIAL_MESH_STATE } from 'reducers/MeshDataState';
 32	import { MeshToolbarActions } from 'actions/MeshToolbarActions';
 33	import { useKialiTranslation } from 'utils/I18nUtils';
 34	
 35	type ReduxStateProps = {
 36	  showGateways: boolean;
 37	  showWaypoints: boolean;
 38	};
 39	
 40	type ReduxDispatchProps = {
 41	  toggleGateways(): void;
 42	  toggleWaypoints(): void;
 43	};
 44	
 45	type MeshSettingsProps = ReduxStateProps &
 46	  ReduxDispatchProps &
 47	  Omit<MeshToolbarState, 'findValue' | 'hideValue' | 'showFindHelp' | 'showLegend'> & {
 48	    disabled: boolean;
 49	  };
 50	
 51	interface DisplayOptionType {
 52	  iconClassName?: string;
 53	  iconColor?: string;
 54	  id: string;
 55	  isChecked: boolean;
 56	  isDisabled?: boolean;
 57	  labelText: string;
 58	  onChange?: () => void;
 59	  tooltip?: React.ReactNode;
 60	}
 61	
 62	const marginBottom = 20;
 63	
 64	const MeshSettingsComponent: React.FC<MeshSettingsProps> = (props: MeshSettingsProps) => {
 65	  const [isOpen, setIsOpen] = React.useState<boolean>(false);
 66	  const { t } = useKialiTranslation();
 67	
 68	  const getMenuOptions = (): React.ReactNode => {
 69	    // map our attributes from redux
 70	    const { showGateways, showWaypoints } = props;
 71	
 72	    // map our dispatchers for redux
 73	    const { toggleGateways, toggleWaypoints } = props;
 74	
 75	    const visibilityOptions: DisplayOptionType[] = [
 76	      {
 77	        id: 'filterGateways',
 78	        isChecked: showGateways,
 79	        labelText: t('Gateways'),
 80	        onChange: toggleGateways,
 81	        tooltip: <div style={{ textAlign: 'left' }}>{t('When enabled, include gateways in the mesh topology.')}</div>
 82	      }
 83	    ];
 84	
 85	    if (serverConfig.ambientEnabled) {
 86	      visibilityOptions.push({
 87	        id: 'filterWaypoints',
 88	        isChecked: showWaypoints,
 89	        labelText: t('Waypoints'),
 90	        onChange: toggleWaypoints,
 91	        tooltip: (
 92	          <div style={{ textAlign: 'left' }}>
 93	            <div>{t('When enabled in an Ambient environment, include waypoints in the mesh topology.')}</div>
 94	          </div>
 95	        )
 96	      });
 97	    }
 98	
 99	    return (
100	      <BoundingClientAwareComponent
101	        className={containerStyle}
102	        maxHeight={{ type: PropertyType.VIEWPORT_HEIGHT_MINUS_TOP, margin: marginBottom }}
103	      >
104	        <div id="graph-display-menu" className={menuStyle} style={{ width: '15em' }}>
105	          <div className={titleStyle}>Show</div>
106	
107	          {visibilityOptions.map((item: DisplayOptionType) => (
108	            <div key={item.id} className={menuEntryStyle}>
109	              <label key={item.id} className={item.tooltip ? itemStyleWithInfo : itemStyleWithoutInfo}>
110	                <Checkbox
111	                  id={item.id}
112	                  isChecked={item.isChecked}
113	                  isDisabled={props.disabled || item.isDisabled}
114	                  label={item.labelText}
115	                  onChange={item.onChange}
116	                />
117	              </label>
118	
119	              {item.tooltip && (
120	                <Tooltip key={`tooltip_${item.id}`} position={TooltipPosition.right} content={item.tooltip}>
121	                  <KialiIcon.Info className={item.iconClassName ?? infoStyle} color={item.iconColor} />
122	                </Tooltip>
123	              )}
124	            </div>
125	          ))}
126	        </div>
127	      </BoundingClientAwareComponent>
128	    );
129	  };
130	
131	  return (
132	    <Dropdown
133	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
134	        <MenuToggle
135	          ref={toggleRef}
136	          id="display-settings"
137	          onClick={() => setIsOpen(!isOpen)}
138	          isExpanded={isOpen}
139	          isDisabled={props.disabled}
140	        >
141	          Display
142	        </MenuToggle>
143	      )}
144	      isOpen={isOpen}
145	      onOpenChange={(isOpen: boolean) => setIsOpen(isOpen)}
146	    >
147	      <DropdownList>{getMenuOptions()}</DropdownList>
148	    </Dropdown>
149	  );
150	};
151	
152	const withURLAwareness = (
153	  MeshSettingsComponent: React.FC<MeshSettingsProps>
154	): React.ComponentClass<MeshSettingsProps> => {
155	  return class extends React.Component<MeshSettingsProps> {
156	    constructor(props: MeshSettingsProps) {
157	      super(props);
158	
159	      // Let URL override current redux state at construction time. Update URL as needed.
160	      this.handleURLBool(
161	        URLParam.MESH_GATEWAYS,
162	        INITIAL_MESH_STATE.toolbarState.showGateways,
163	        props.showGateways,
164	        props.toggleGateways
165	      );
166	
167	      this.handleURLBool(
168	        URLParam.MESH_WAYPOINTS,
169	        INITIAL_MESH_STATE.toolbarState.showWaypoints,
170	        props.showWaypoints,
171	        props.toggleWaypoints
172	      );
173	    }
174	
175	    private handleURLBool = (
176	      param: URLParam,
177	      paramDefault: boolean,
178	      reduxValue: boolean,
179	      reduxToggle: () => void
180	    ): void => {
181	      const urlValue = HistoryManager.getBooleanParam(param);
182	
183	      if (urlValue !== undefined) {
184	        if (urlValue !== reduxValue) {
185	          reduxToggle();
186	        }
187	      } else if (reduxValue !== paramDefault) {
188	        HistoryManager.setParam(param, String(reduxValue));
189	      }
190	    };
191	
192	    private alignURLBool = (param: URLParam, paramDefault: boolean, prev: boolean, curr: boolean): void => {
193	      if (prev === curr) {
194	        return;
195	      }
196	
197	      if (curr === paramDefault) {
198	        HistoryManager.deleteParam(param);
199	      } else {
200	        HistoryManager.setParam(param, String(curr));
201	      }
202	    };
203	
204	    componentDidUpdate(prev: MeshSettingsProps): void {
205	      this.alignURLBool(
206	        URLParam.MESH_GATEWAYS,
207	        INITIAL_MESH_STATE.toolbarState.showGateways,
208	        prev.showGateways,
209	        this.props.showGateways
210	      );
211	      this.alignURLBool(
212	        URLParam.MESH_WAYPOINTS,
213	        INITIAL_MESH_STATE.toolbarState.showWaypoints,
214	        prev.showWaypoints,
215	        this.props.showWaypoints
216	      );
217	    }
218	
219	    render(): React.ReactNode {
220	      return <MeshSettingsComponent {...this.props} />;
221	    }
222	  };
223	};
224	
225	// Allow Redux to map sections of our global app state to our props
226	const mapStateToProps = (state: KialiAppState): ReduxStateProps => ({
227	  showGateways: state.mesh.toolbarState.showGateways,
228	  showWaypoints: state.mesh.toolbarState.showWaypoints
229	});
230	
231	// Map our actions to Redux
232	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxDispatchProps => {
233	  return {
234	    toggleGateways: bindActionCreators(MeshToolbarActions.toggleGateways, dispatch),
235	    toggleWaypoints: bindActionCreators(MeshToolbarActions.toggleWaypoints, dispatch)
236	  };
237	};
238	
239	export const MeshSettings = connect(mapStateToProps, mapDispatchToProps)(withURLAwareness(MeshSettingsComponent));

